import React from 'react';
import { Menu, X, User, LogIn } from 'lucide-react';
import { Link } from 'react-router-dom';

interface NavbarProps {
  isLoggedIn?: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ isLoggedIn = false }) => {
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);

  return (
    <header className="bg-gradient-to-r from-indigo-700 to-purple-800 shadow-lg sticky top-0 z-50">
      <div className="container mx-auto px-4 py-4">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-3">
            <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center">
              <div className="w-8 h-8 bg-gradient-to-r from-indigo-600 to-purple-700 rounded-full flex items-center justify-center">
                <span className="text-white font-bold text-lg">D</span>
              </div>
            </div>
            <h1 className="text-3xl font-bold text-white drop-shadow-lg">DHARMASIKHARA</h1>
          </Link>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex space-x-1">
            <Link to="/" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Home</Link>
            <Link to="/scenarios" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Scenarios</Link>
            <Link to="/marketplace" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Marketplace</Link>
            <Link to="/dashboard" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Dashboard</Link>
            <Link to="/multiplayer" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Multiplayer</Link>
            <Link to="/about" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">About</Link>
            <Link to="/contact" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Contact</Link>
          </nav>

          <div className="hidden md:flex items-center space-x-4">
            {isLoggedIn ? (
              <div className="flex items-center space-x-2 bg-white/20 px-4 py-2 rounded-lg">
                <User className="w-5 h-5 text-white" />
                <span className="text-white font-medium">John Doe</span>
              </div>
            ) : (
              <>
                <Link to="/login" className="text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition duration-300">Sign In</Link>
                <button className="bg-white text-indigo-700 px-6 py-2 rounded-lg hover:bg-gray-100 transition duration-300 font-bold shadow-md">
                  Get Started
                </button>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <button 
            className="md:hidden text-white"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>

        {/* Mobile Navigation */}
        {isMenuOpen && (
          <div className="md:hidden mt-4 py-4 border-t border-white/20">
            <nav className="flex flex-col space-y-2">
              <Link to="/" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Home</Link>
              <Link to="/scenarios" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Scenarios</Link>
              <Link to="/marketplace" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Marketplace</Link>
              <Link to="/dashboard" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Dashboard</Link>
              <Link to="/multiplayer" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Multiplayer</Link>
              <Link to="/about" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>About</Link>
              <Link to="/contact" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Contact</Link>
            </nav>
            <div className="mt-6 flex flex-col space-y-3">
              {isLoggedIn ? (
                <div className="flex items-center space-x-2 bg-white/20 px-4 py-3 rounded-lg">
                  <User className="w-5 h-5 text-white" />
                  <span className="text-white font-medium">John Doe</span>
                </div>
              ) : (
                <>
                  <Link to="/login" className="text-white hover:bg-white/20 px-4 py-3 rounded-lg font-medium" onClick={() => setIsMenuOpen(false)}>Sign In</Link>
                  <button className="bg-white text-indigo-700 px-4 py-3 rounded-lg hover:bg-gray-100 transition duration-300 font-bold">
                    Get Started
                  </button>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </header>
  );
};

export default Navbar;
